UPDATE market_sector_ranking_config
SET run_claim_token = NULL, run_claimed_at = NULL
WHERE id = #{id} AND run_claim_token = #{token}

UPDATE market_sector_ranking_config
SET execution_state = #{state}, next_retry_at = #{nextRetryAt},
    consecutive_failures = consecutive_failures + 1,
    last_error_code = #{errorCode}, last_error_message = #{errorMessage}
WHERE id = #{id} AND run_claim_token = #{token}
